INSERT INTO public.pinterest_pins (title, description, board, pin_type, link_url, group_name, group_slug, headline, subtext, needs_photo, status, hashtags, category, sort_order) VALUES
('How Well Do You Know BTS? Take the Quiz', 'Are you a true ARMY? Test your BTS knowledge with fan-made trivia covering their discography, members, and milestones. From No More Dream to Dynamite - can you score 10/10? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'BTS', 'bts', 'How Well Do You Know BTS?', 'Only true ARMYs get a perfect score', true, 'draft', ARRAY['#kpop', '#BTS', '#ARMY', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 1),
('How Well Do You Know BLACKPINK? Take the Quiz', 'BLINK alert! Test your BLACKPINK knowledge with fan-made quiz questions. From Whistle to Pink Venom - how much do you really know about Jisoo, Jennie, Rose and Lisa? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'BLACKPINK', 'blackpink', 'How Well Do You Know BLACKPINK?', 'True BLINKs will ace this quiz', true, 'draft', ARRAY['#kpop', '#BLACKPINK', '#BLINK', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 2),
('How Well Do You Know Stray Kids? Take the Quiz', 'Stay strong! Test your Stray Kids knowledge from their self-produced tracks to member birthdays. Can you score 10/10 on this fan-made SKZ quiz? Play free at kpopquiz.org! #kpop #StrayKids #STAY', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'Stray Kids', 'stray-kids', 'How Well Do You Know Stray Kids?', 'Real STAYs will get a perfect score', true, 'draft', ARRAY['#kpop', '#StrayKids', '#SKZ', '#STAY', '#kpopquiz'], 'quiz_link', 3),
('How Well Do You Know TWICE? Take the Quiz', 'ONCEs, it''s your time to shine! Test your TWICE knowledge with fan-made trivia. From Cheer Up to FANCY - do you know all 9 members'' facts? Play free at kpopquiz.org! #kpop #TWICE #ONCE', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'TWICE', 'twice', 'How Well Do You Know TWICE?', 'Can you score 10/10 on this ONCE quiz?', true, 'draft', ARRAY['#kpop', '#TWICE', '#ONCE', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 4),
('How Well Do You Know aespa? Take the Quiz', 'MY, are you the biggest aespa fan? Test your knowledge of Karina, Giselle, Winter and Ningning with fan-made trivia. From Black Mamba to Spicy - can you score 10/10? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'aespa', 'aespa', 'How Well Do You Know aespa?', 'Only true MY fans ace this quiz', true, 'draft', ARRAY['#kpop', '#aespa', '#MY', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 5),
('How Well Do You Know NewJeans? Take the Quiz', 'Bunnies, are you ready? Test your NewJeans knowledge with fan-made trivia. From Hype Boy to OMG - how well do you really know Minji, Hanni, Danielle, Haerin and Hyein? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'NewJeans', 'newjeans', 'How Well Do You Know NewJeans?', 'The ultimate Bunnies knowledge test', true, 'draft', ARRAY['#kpop', '#NewJeans', '#Bunnies', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 6),
('How Well Do You Know SEVENTEEN? Take the Quiz', 'CARATs assemble! Test your SEVENTEEN knowledge with fan-made trivia. 13 members, 3 units, countless hits - do you know it all? From Adore U to Fear, play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'SEVENTEEN', 'seventeen', 'How Well Do You Know SEVENTEEN?', 'CARATs only: can you score perfect?', true, 'draft', ARRAY['#kpop', '#SEVENTEEN', '#CARAT', '#SVT', '#kpopquiz'], 'quiz_link', 7),
('How Well Do You Know EXO? Take the Quiz', 'EXO-L, show your love! Test your EXO knowledge with fan-made trivia questions. From MAMA to Power - how well do you know Suho, Baekhyun, Chanyeol and the squad? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'EXO', 'exo', 'How Well Do You Know EXO?', 'A quiz only true EXO-L can ace', true, 'draft', ARRAY['#kpop', '#EXO', '#EXOL', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 8),
('How Well Do You Know (G)I-DLE? Take the Quiz', 'Neverlands, it''s your time! Test your (G)I-DLE knowledge with fan-made trivia. From LATATA to Tomboy - do you know all about Miyeon, Minnie, Soyeon, Yuqi and Shuhua? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', '(G)I-DLE', 'g-i-dle', 'How Well Do You Know (G)I-DLE?', 'Neverland fans only', true, 'draft', ARRAY['#kpop', '#GIDLE', '#Neverland', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 9),
('How Well Do You Know IVE? Take the Quiz', 'DIVE into the quiz! Test your IVE knowledge with fan-made trivia. From ELEVEN to I AM - do you know Gaeul, Yujin, Rei, Wonyoung, Liz and Leeseo? Play free at kpopquiz.org! #kpop #IVE', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'IVE', 'ive', 'How Well Do You Know IVE?', 'Can you score 10/10 on this DIVE quiz?', true, 'draft', ARRAY['#kpop', '#IVE', '#DIVE', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 10),
('How Well Do You Know LE SSERAFIM? Take the Quiz', 'FEARNOT! Test your LE SSERAFIM knowledge with fan-made trivia. From Fearless to Perfect Night - how well do you know Sakura, Chaewon, Yunjin, Kazuha and Eunchae? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'LE SSERAFIM', 'le-sserafim', 'How Well Do You Know LE SSERAFIM?', 'FEARLESS fans will ace this', true, 'draft', ARRAY['#kpop', '#LESSERAFIM', '#FEARNOT', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 11),
('How Well Do You Know NCT? Take the Quiz', 'NCTzen, how well do you know SM''s unlimited group? Test your knowledge of NCT''s concept, members, and hits. From Cherry Bomb to Sticker - play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'NCT', 'nct', 'How Well Do You Know NCT?', 'An NCTzen quiz with no limits', true, 'draft', ARRAY['#kpop', '#NCT', '#NCTzen', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 12),
('How Well Do You Know Red Velvet? Take the Quiz', 'ReVeluv, show what you know! Test your Red Velvet knowledge with fan-made trivia. From Happiness to Psycho - how well do you know Irene, Seulgi, Wendy, Joy and Yeri? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'Red Velvet', 'red-velvet', 'How Well Do You Know Red Velvet?', 'Red or Velvet - can you ace both?', true, 'draft', ARRAY['#kpop', '#RedVelvet', '#ReVeluv', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 13),
('How Well Do You Know ATEEZ? Take the Quiz', 'ATINY, are you ready for the challenge? Test your ATEEZ knowledge from Treasure to The World. From Pirate King to Fireworks - play free at kpopquiz.org and prove your love!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'ATEEZ', 'ateez', 'How Well Do You Know ATEEZ?', 'ATINY prove your dedication here', true, 'draft', ARRAY['#kpop', '#ATEEZ', '#ATINY', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 14),
('How Well Do You Know ENHYPEN? Take the Quiz', 'ENGENE, prove your dedication! Test your ENHYPEN knowledge with fan-made trivia. From Border: Day One to Dark Blood - how well do you know the 7 members? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'ENHYPEN', 'enhypen', 'How Well Do You Know ENHYPEN?', 'The ultimate ENGENE knowledge test', true, 'draft', ARRAY['#kpop', '#ENHYPEN', '#ENGENE', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 15),
('How Well Do You Know TXT? Take the Quiz', 'MOA, this quiz is for you! Test your TOMORROW X TOGETHER knowledge with fan-made trivia. From Crown to Sugar Rush Ride - how well do you know Yeonjun, Soobin, Beomgyu, Taehyun and Huening Kai?', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'TXT', 'txt', 'How Well Do You Know TXT?', 'A quiz only true MOA can pass', true, 'draft', ARRAY['#kpop', '#TXT', '#MOA', '#TOMORROWXTOGETHER', '#kpopquiz'], 'quiz_link', 16),
('How Well Do You Know ITZY? Take the Quiz', 'MIDZY, do you really know ITZY? Test your knowledge with fan-made trivia from Dalla Dalla to Cake. Do you know Yeji, Lia, Ryujin, Chaeryeong and Yuna? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'ITZY', 'itzy', 'How Well Do You Know ITZY?', 'MIDZY only: score 10/10', true, 'draft', ARRAY['#kpop', '#ITZY', '#MIDZY', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 17),
('How Well Do You Know NMIXX? Take the Quiz', 'NSWer, are you ready? Test your NMIXX knowledge from their mixx pop concept to hits like O.O and Love Me Like This. Can you ace this fan-made quiz? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'NMIXX', 'nmixx', 'How Well Do You Know NMIXX?', 'The NSWer ultimate knowledge test', true, 'draft', ARRAY['#kpop', '#NMIXX', '#NSWer', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 18),
('How Well Do You Know STAYC? Take the Quiz', 'SWITH, how well do you know STAYC? Test your knowledge with fan-made trivia covering their TEEN FRESH concept and hits from SO BAD to Teddy Bear. Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'STAYC', 'stayc', 'How Well Do You Know STAYC?', 'SWITH fans will ace this quiz', true, 'draft', ARRAY['#kpop', '#STAYC', '#SWITH', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 19),
('How Well Do You Know MONSTA X? Take the Quiz', 'Monbebe, prove your love! Test your MONSTA X knowledge with fan-made trivia from All In to Rush Hour. How well do you know Shownu, Minhyuk, Kihyun, Hyungwon, Joohoney and I.M? Play free!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'MONSTA X', 'monsta-x', 'How Well Do You Know MONSTA X?', 'Monbebe prove your dedication', true, 'draft', ARRAY['#kpop', '#MONSTAX', '#Monbebe', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 20),
('How Well Do You Know GOT7? Take the Quiz', 'IGOT7, step up! Test your GOT7 knowledge with fan-made trivia from A to Never Ever. Do you know all 7 members'' facts and the group''s legendary history? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'GOT7', 'got7', 'How Well Do You Know GOT7?', 'IGOT7 only: ace this quiz', true, 'draft', ARRAY['#kpop', '#GOT7', '#IGOT7', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 21),
('How Well Do You Know MAMAMOO? Take the Quiz', 'Moomoo, are you the biggest MAMAMOO fan? Test your knowledge of Solar, Moonbyul, Wheein and Hwasa with fan-made trivia. From Mr. Ambiguous to Egotistic - play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', 'MAMAMOO', 'mamamoo', 'How Well Do You Know MAMAMOO?', 'True Moomoos will score 10/10', true, 'draft', ARRAY['#kpop', '#MAMAMOO', '#Moomoo', '#kpopquiz', '#kpoptrivia'], 'quiz_link', 22),
