('The Ultimate K-pop Girl Group Knowledge Quiz', 'Think you know your K-pop girl groups? Test your knowledge of BLACKPINK, TWICE, aespa, NewJeans, IVE and more with this ultimate fan-made quiz. Who will score 10/10? Play free at kpopquiz.org!', 'K-pop Quizzes', 'quiz_link', 'https://kpopquiz.org', NULL, NULL, 'Ultimate K-pop Girl Group Quiz', 'How many will you get right?', true, 'draft', ARRAY['#kpop', '#kpopgirlgroup', '#kpopquiz', '#kpoptrivia', '#kpopfan'], 'quiz_link', 30);
INSERT INTO public.pinterest_pins (title, description, board, pin_type, link_url, group_name, group_slug, headline, subtext, fact_date, needs_photo, status, hashtags, category, sort_order) VALUES
INSERT INTO public.pinterest_pins (title, description, board, pin_type, link_url, group_name, group_slug, headline, subtext, needs_photo, status, hashtags, category, sort_order) VALUES
('Did You Know? BTS''s V Fact', 'Did you know BTS''s V (Kim Taehyung) has been named one of the most Googled people in the world multiple years in a row? Test your BTS knowledge at kpopquiz.org! #BTS #kpoptrivia', 'K-pop Fun Facts', 'did_you_know', NULL, 'BTS', 'bts', 'BTS''s V is one of the most Googled people on Earth', 'Multiple years running - his global fame is undeniable', false, 'draft', ARRAY['#kpop', '#BTS', '#V', '#ARMY', '#kpoptrivia'], 'did_you_know', 111),
('Did You Know? BLACKPINK Lisa is Thai', 'Did you know BLACKPINK''s Lisa (Lalisa Manobal) is from Thailand, not Korea? She moved to Seoul at 14 to train at YG Entertainment and became one of K-pop''s most iconic performers. #BLACKPINK', 'K-pop Fun Facts', 'did_you_know', NULL, 'BLACKPINK', 'blackpink', 'BLACKPINK''s Lisa is from Thailand, not Korea', 'She moved to Seoul at age 14 to train at YG', false, 'draft', ARRAY['#kpop', '#BLACKPINK', '#Lisa', '#BLINK', '#kpoptrivia'], 'did_you_know', 112),
('Did You Know? Stray Kids Felix From Australia', 'Did you know Stray Kids has TWO Australian members? Felix Lee is from Sydney, just like leader Bang Chan. Both trained at JYP before debuting together in 2018. #StrayKids #kpoptrivia', 'K-pop Fun Facts', 'did_you_know', NULL, 'Stray Kids', 'stray-kids', 'Stray Kids has TWO members from Australia', 'Bang Chan AND Felix are both from Sydney', false, 'draft', ARRAY['#kpop', '#StrayKids', '#Felix', '#BangChan', '#kpoptrivia'], 'did_you_know', 113),
('Did You Know? BTS RM Self-Taught English', 'Did you know BTS''s RM taught himself English primarily by watching the US sitcom "Friends" with Korean subtitles? He now speaks fluent English and serves as the group''s main interpreter. #BTS #RM', 'K-pop Fun Facts', 'did_you_know', NULL, 'BTS', 'bts', 'BTS''s RM learned English by watching "Friends"', 'Now he speaks fluently and translates for the group', false, 'draft', ARRAY['#kpop', '#BTS', '#RM', '#ARMY', '#kpoptrivia'], 'did_you_know', 114),
('Did You Know? TWICE Tzuyu Is Taiwanese', 'Did you know TWICE''s Tzuyu (Chou Tzuyu) is from Tainan, Taiwan? She was involved in a political controversy in 2016 but returned stronger as one of TWICE''s most beloved members. #TWICE', 'K-pop Fun Facts', 'did_you_know', NULL, 'TWICE', 'twice', 'TWICE''s Tzuyu is from Tainan, Taiwan', 'One of K-pop''s most recognizable international members', false, 'draft', ARRAY['#kpop', '#TWICE', '#Tzuyu', '#ONCE', '#kpoptrivia'], 'did_you_know', 115),
('Did You Know? GOT7 Mark From LA', 'Did you know GOT7''s Mark Tuan is from Los Angeles, California? He was the first American member to join a JYP Entertainment group and is known for his martial arts tricking skills. #GOT7', 'K-pop Fun Facts', 'did_you_know', NULL, 'GOT7', 'got7', 'GOT7''s Mark is from Los Angeles, California', 'The first American to join a JYP Entertainment group', false, 'draft', ARRAY['#kpop', '#GOT7', '#Mark', '#IGOT7', '#kpoptrivia'], 'did_you_know', 116),
('Did You Know? EXO Superpowers Concept', 'Did you know each EXO member was assigned a unique superpower before debut? Their pre-debut short films revealed powers like fire, ice, telekinesis, healing, and time control for each member. #EXO', 'K-pop Fun Facts', 'did_you_know', NULL, 'EXO', 'exo', 'Every EXO member was assigned a unique superpower', 'The concept was revealed through pre-debut short films', false, 'draft', ARRAY['#kpop', '#EXO', '#EXOL', '#kpoptrivia', '#kpoplore'], 'did_you_know', 117),
('Did You Know? NewJeans No Teasers', 'Did you know NewJeans broke K-pop convention by releasing their debut with almost zero pre-promotion teaser content? No concept photos, no individual teasers - just the music. Fans were stunned. #NewJeans', 'K-pop Fun Facts', 'did_you_know', NULL, 'NewJeans', 'newjeans', 'NewJeans broke every K-pop marketing rule at debut', 'No teasers, no concept photos - just the music', false, 'draft', ARRAY['#kpop', '#NewJeans', '#Bunnies', '#kpoptrivia', '#kpopmarketing'], 'did_you_know', 118),
('Did You Know? BLACKPINK Rose From NZ', 'Did you know BLACKPINK''s Rose (Roseanne Park) was born in New Zealand and grew up in Australia? She auditioned for YG at a talent show in Melbourne before moving to Korea. #BLACKPINK #Rose', 'K-pop Fun Facts', 'did_you_know', NULL, 'BLACKPINK', 'blackpink', 'BLACKPINK''s Rose is from New Zealand, raised in Australia', 'She auditioned for YG at a Melbourne talent show', false, 'draft', ARRAY['#kpop', '#BLACKPINK', '#Rose', '#BLINK', '#kpoptrivia'], 'did_you_know', 119),
('Did You Know? SEVENTEEN Woozi Composed Hits', 'Did you know SEVENTEEN''s Woozi composed some of their biggest hits starting from when he was a teenager in training? He is one of K-pop''s youngest and most prolific songwriters. #SEVENTEEN', 'K-pop Fun Facts', 'did_you_know', NULL, 'SEVENTEEN', 'seventeen', 'SEVENTEEN''s Woozi started composing hits as a teen trainee', 'One of K-pop''s youngest prolific songwriters ever', false, 'draft', ARRAY['#kpop', '#SEVENTEEN', '#Woozi', '#CARAT', '#kpoptrivia'], 'did_you_know', 120),
('Did You Know? aespa AE Avatars', 'Did you know each aespa member has a digital avatar counterpart called "ae"? ae-Karina, ae-Giselle, ae-Winter, and ae-Ningning exist in a virtual world and appear in their music videos. #aespa', 'K-pop Fun Facts', 'did_you_know', NULL, 'aespa', 'aespa', 'Every aespa member has a digital AI avatar called "ae-"', 'The avatars appear in music videos and the SMCU lore', false, 'draft', ARRAY['#kpop', '#aespa', '#MY', '#kpoptrivia', '#SMCU'], 'did_you_know', 121),
('Did You Know? IVE Wonyoung Was #1 Pick', 'Did you know IVE''s Jang Wonyoung was the #1 overall pick on Mnet''s Produce 48 in 2018, becoming IZ*ONE''s center? She debuted again with IVE in 2021 and became a K-pop icon. #IVE #Wonyoung', 'K-pop Fun Facts', 'did_you_know', NULL, 'IVE', 'ive', 'IVE''s Wonyoung was the #1 pick on Produce 48', 'She became the center of IZ*ONE before IVE debut', false, 'draft', ARRAY['#kpop', '#IVE', '#Wonyoung', '#DIVE', '#kpoptrivia'], 'did_you_know', 122),
('Did You Know? BTS Was Almost a Solo Act', 'Did you know HYBE''s founder Bang Si-hyuk originally planned BTS to be a solo rap project for RM? After hearing how well the members worked together, the concept evolved into a 7-member group. #BTS', 'K-pop Fun Facts', 'did_you_know', NULL, 'BTS', 'bts', 'BTS was originally planned as RM''s solo rap project', 'The group format was decided after seeing their chemistry', false, 'draft', ARRAY['#kpop', '#BTS', '#RM', '#ARMY', '#kpoptrivia'], 'did_you_know', 123),
('Did You Know? ATEEZ Hongjoong Produces Music', 'Did you know ATEEZ''s Hongjoong is a self-taught music producer who creates and produces many of their songs? He learned production independently and now oversees much of ATEEZ''s sound. #ATEEZ', 'K-pop Fun Facts', 'did_you_know', NULL, 'ATEEZ', 'ateez', 'ATEEZ''s Hongjoong is a self-taught music producer', 'He learned production independently and leads the group''s sound', false, 'draft', ARRAY['#kpop', '#ATEEZ', '#Hongjoong', '#ATINY', '#kpoptrivia'], 'did_you_know', 124),
('Did You Know? TXT Name Meaning', 'Did you know TXT stands for "Tomorrow X Together"? The "X" in the middle is pronounced "by" in Korean, meaning "Tomorrow By Together" - symbolizing the connection between the members and fans. #TXT', 'K-pop Fun Facts', 'did_you_know', NULL, 'TXT', 'txt', 'TXT stands for "Tomorrow X Together"', 'The X is read as "by" in Korean - Tomorrow BY Together', false, 'draft', ARRAY['#kpop', '#TXT', '#MOA', '#TOMORROWXTOGETHER', '#kpoptrivia'], 'did_you_know', 125),
('Did You Know? NCT Has No Member Limit', 'Did you know NCT was designed to have no fixed member cap? SM Entertainment envisioned it as a "rotating" system where members could be added indefinitely. Over 23 members have joined since 2016. #NCT', 'K-pop Fun Facts', 'did_you_know', NULL, 'NCT', 'nct', 'NCT was designed to have unlimited members', 'SM''s vision: a group that grows forever', false, 'draft', ARRAY['#kpop', '#NCT', '#NCTzen', '#kpoptrivia', '#kpoplore'], 'did_you_know', 126),
('Did You Know? MAMAMOO All Self-Titled', 'Did you know MAMAMOO''s albums are titled with sounds like "Yellow Flower", "Red Moon", "White Wind" - forming a spectrum? Their discography is designed to tell a color-coded emotional story. #MAMAMOO', 'K-pop Fun Facts', 'did_you_know', NULL, 'MAMAMOO', 'mamamoo', 'MAMAMOO''s albums form a deliberate color-coded spectrum', 'Yellow, Red, White - their discography tells a color story', false, 'draft', ARRAY['#kpop', '#MAMAMOO', '#Moomoo', '#kpoptrivia', '#kpoplore'], 'did_you_know', 127),
('Did You Know? (G)I-DLE Soyeon Self-Produces', 'Did you know (G)I-DLE''s leader Soyeon writes and produces most of their songs herself? She is one of the only female idol-producers in K-pop and has been doing it since their 2018 debut. #GIDLE', 'K-pop Fun Facts', 'did_you_know', NULL, '(G)I-DLE', 'g-i-dle', '(G)I-DLE''s Soyeon is one of few female idol-producers in K-pop', 'She has been writing and producing since their 2018 debut', false, 'draft', ARRAY['#kpop', '#GIDLE', '#Soyeon', '#Neverland', '#kpoptrivia'], 'did_you_know', 128),
('Did You Know? BTOB Peniel Is American', 'Did you know BTOB''s Peniel (Shin Dong-geun) was born and raised in Chicago, Illinois? He is Korean-American and moved to Korea to pursue his K-pop dream as a teenager. #BTOB #Peniel', 'K-pop Fun Facts', 'did_you_know', NULL, 'BTOB', 'btob', 'BTOB''s Peniel is Korean-American from Chicago', 'He moved from Illinois to Korea to become a K-pop idol', false, 'draft', ARRAY['#kpop', '#BTOB', '#Peniel', '#Melody', '#kpoptrivia'], 'did_you_know', 129),
('Did You Know? LE SSERAFIM Name Is Anagram', 'Did you know "LE SSERAFIM" is a perfect anagram of "I''M FEARLESS"? The name reflects the group''s fearless philosophy and empowerment message. They debuted in 2022 under HYBE and Source Music. #LESSERAFIM', 'K-pop Fun Facts', 'did_you_know', NULL, 'LE SSERAFIM', 'le-sserafim', 'LE SSERAFIM is an anagram of "I''M FEARLESS"', 'The hidden message is right there in the group name', false, 'draft', ARRAY['#kpop', '#LESSERAFIM', '#FEARNOT', '#kpoptrivia', '#kpopfact'], 'did_you_know', 130),
('Did You Know? Stray Kids 3RACHA Sub-Unit', 'Did you know Bang Chan, Changbin, and Han formed a producing sub-unit called 3RACHA while still trainees? They released music independently on SoundCloud before Stray Kids even debuted. #SKZ', 'K-pop Fun Facts', 'did_you_know', NULL, 'Stray Kids', 'stray-kids', 'Bang Chan, Changbin and Han released music as 3RACHA pre-debut', 'They put songs on SoundCloud before Stray Kids even existed', false, 'draft', ARRAY['#kpop', '#StrayKids', '#3RACHA', '#STAY', '#kpoptrivia'], 'did_you_know', 131),
('Did You Know? Red Velvet Yeri Joined Later', 'Did you know Red Velvet originally debuted as a 4-member group? Yeri was added as a 5th member in March 2015, about 7 months after the group''s debut. She was only 16 at the time. #RedVelvet', 'K-pop Fun Facts', 'did_you_know', NULL, 'Red Velvet', 'red-velvet', 'Red Velvet originally debuted without Yeri', 'She joined 7 months later at just 16 years old', false, 'draft', ARRAY['#kpop', '#RedVelvet', '#Yeri', '#ReVeluv', '#kpoptrivia'], 'did_you_know', 132),
('Did You Know? ENHYPEN Jungwon Leader Age', 'Did you know ENHYPEN''s leader Yang Jungwon was only 17 years old when he was chosen as the group''s leader? He became one of the youngest leaders of a 4th gen K-pop group at debut. #ENHYPEN', 'K-pop Fun Facts', 'did_you_know', NULL, 'ENHYPEN', 'enhypen', 'ENHYPEN''s leader Jungwon was only 17 at debut', 'One of the youngest leaders of a 4th gen K-pop group', false, 'draft', ARRAY['#kpop', '#ENHYPEN', '#Jungwon', '#ENGENE', '#kpoptrivia'], 'did_you_know', 133),
('Did You Know? EXO Originally Had 12 Members', 'Did you know EXO originally had 12 members? Over the years Kris, Luhan, Tao, Lay (limited activity), Xiumin, and D.O. left or paused, leaving 6 active members: Suho, Baekhyun, Chanyeol, Kai, and Sehun. #EXO', 'K-pop Fun Facts', 'did_you_know', NULL, 'EXO', 'exo', 'EXO started with 12 members in 2012', 'The lineup has changed significantly over the years', false, 'draft', ARRAY['#kpop', '#EXO', '#EXOL', '#kpoptrivia', '#kpophistory'], 'did_you_know', 134),
('Did You Know? TWICE Members From 3 Countries', 'Did you know TWICE has members from 3 different countries? 5 are Korean, 3 are Japanese (Momo, Sana, Mina), and 1 is Taiwanese (Tzuyu). Their diverse lineup helped them conquer all of Asia. #TWICE', 'K-pop Fun Facts', 'did_you_know', NULL, 'TWICE', 'twice', 'TWICE has members from Korea, Japan, and Taiwan', 'Their multinational lineup helped them dominate Asia', false, 'draft', ARRAY['#kpop', '#TWICE', '#ONCE', '#kpoptrivia', '#kpopfact'], 'did_you_know', 135),
('Did You Know? IVE "After Like" Samples Diana Ross', 'Did you know IVE''s hit "After Like" (2022) samples Diana Ross''s 1980 classic "I''m Coming Out"? The unexpected sample introduced many young fans to the disco legend. #IVE #DianaRoss', 'K-pop Fun Facts', 'did_you_know', NULL, 'IVE', 'ive', 'IVE''s "After Like" secretly samples a 1980 Diana Ross song', '"I''m Coming Out" introduced to a whole new generation', false, 'draft', ARRAY['#kpop', '#IVE', '#AfterLike', '#DianaRoss', '#kpoptrivia'], 'did_you_know', 136),
('Did You Know? GOT7 Bambam Is Thai', 'Did you know GOT7''s BamBam (Kunpimook Bhuwakul) is from Bangkok, Thailand? Like Lisa from BLACKPINK, he moved to Korea as a teenager to pursue his K-pop dreams at JYP Entertainment. #GOT7', 'K-pop Fun Facts', 'did_you_know', NULL, 'GOT7', 'got7', 'GOT7''s BamBam is from Bangkok, Thailand', 'He moved to Korea as a teen to train at JYP', false, 'draft', ARRAY['#kpop', '#GOT7', '#BamBam', '#IGOT7', '#kpoptrivia'], 'did_you_know', 137),
('Did You Know? MONSTA X Formed From Survival Show', 'Did you know MONSTA X was formed through the Mnet survival show "No.Mercy" in 2015? The intense competition show ultimately selected 7 members for the debut lineup. #MONSTAX #kpoptrivia', 'K-pop Fun Facts', 'did_you_know', NULL, 'MONSTA X', 'monsta-x', 'MONSTA X was formed through survival show "No.Mercy"', '7 members were chosen through intense competition in 2015', false, 'draft', ARRAY['#kpop', '#MONSTAX', '#Monbebe', '#kpoptrivia', '#kpophistory'], 'did_you_know', 138),
('Did You Know? SHINee Taemin Debuted at 14', 'Did you know SHINee''s Taemin was only 14 years old when the group debuted in 2008? He is now considered one of K-pop''s greatest ever dancers and a successful solo artist in his own right. #SHINee', 'K-pop Fun Facts', 'did_you_know', NULL, 'SHINee', 'shinee', 'SHINee''s Taemin debuted at just 14 years old in 2008', 'He became one of K-pop''s all-time greatest dancers', false, 'draft', ARRAY['#kpop', '#SHINee', '#Taemin', '#Shawol', '#kpoptrivia'], 'did_you_know', 139),
('Did You Know? NMIXX O.O Was Controversial', 'Did you know NMIXX''s debut song "O.O" was considered one of the most controversial K-pop debuts? Its sudden genre switches divided fans but also made it unforgettable and endlessly discussed. #NMIXX', 'K-pop Fun Facts', 'did_you_know', NULL, 'NMIXX', 'nmixx', '"O.O" by NMIXX was one of K-pop''s most debated debuts', 'Its genre switches divided fans but made history', false, 'draft', ARRAY['#kpop', '#NMIXX', '#NSWer', '#kpoptrivia', '#kpopfact'], 'did_you_know', 140),
('Did You Know? Dreamcatcher Dark Concept', 'Did you know Dreamcatcher is one of the only K-pop groups to maintain a consistent dark/rock concept across their entire discography? Their concept, based on nightmares, has never changed since debut. #DC', 'K-pop Fun Facts', 'did_you_know', NULL, 'Dreamcatcher', 'dreamcatcher', 'Dreamcatcher has never changed their nightmare concept', 'The only K-pop group with 100% consistent dark rock branding', false, 'draft', ARRAY['#kpop', '#Dreamcatcher', '#InSomnia', '#kpoptrivia', '#kpoprock'], 'did_you_know', 141),
('Did You Know? BTS Donated to BLM', 'Did you know BTS and HYBE donated $1 million to the Black Lives Matter movement in 2020? Within 24 hours, the ARMY fandom matched that donation through a fan-led campaign called "MatchAMillion". #BTS', 'K-pop Fun Facts', 'did_you_know', NULL, 'BTS', 'bts', 'BTS donated $1M to BLM - and ARMY matched it in 24 hours', 'The fan-led "MatchAMillion" campaign raised $1M more overnight', false, 'draft', ARRAY['#kpop', '#BTS', '#ARMY', '#kpoptrivia', '#kpopimpact'], 'did_you_know', 142),
('Did You Know? BLACKPINK 4 Members YG', 'Did you know BLACKPINK had only 4 members despite YG Entertainment originally training many more? A documentary revealed that additional members were eliminated through internal evaluations before debut. #BLACKPINK', 'K-pop Fun Facts', 'did_you_know', NULL, 'BLACKPINK', 'blackpink', 'Many more than 4 trainees competed to debut as BLACKPINK', 'YG narrowed it down through extensive internal evaluations', false, 'draft', ARRAY['#kpop', '#BLACKPINK', '#BLINK', '#kpoptrivia', '#YGEntertainment'], 'did_you_know', 143),
('Did You Know? ITZY No Center Concept', 'Did you know ITZY was the first JYP girl group to not have an official "center" or "visual" position? JYP said all 5 members are equally important - a deliberate break from K-pop norms. #ITZY', 'K-pop Fun Facts', 'did_you_know', NULL, 'ITZY', 'itzy', 'ITZY has no official "center" or "visual" position', 'JYP deliberately broke the K-pop lineup norm for them', false, 'draft', ARRAY['#kpop', '#ITZY', '#MIDZY', '#kpoptrivia', '#kpopfact'], 'did_you_know', 144),
('Did You Know? aespa Black Mamba Fastest 100M', 'Did you know aespa''s "Black Mamba" (2020) set the record for the fastest K-pop group debut MV to reach 100 million YouTube views at the time? A stunning achievement for a brand new group. #aespa', 'K-pop Fun Facts', 'did_you_know', NULL, 'aespa', 'aespa', '"Black Mamba" was the fastest K-pop group debut MV to 100M views', 'An extraordinary record for a brand new group in 2020', false, 'draft', ARRAY['#kpop', '#aespa', '#BlackMamba', '#MY', '#kpoptrivia'], 'did_you_know', 145),
('Did You Know? EXO Members Have Unique Fan Names', 'Did you know each EXO member has a dedicated sub-fandom within EXO-L? For example, Baekhyun has "Byun Baekhyun''s BB" fans, and Kai fans are called "Kaiser". These sub-fandoms are very active. #EXO', 'K-pop Fun Facts', 'did_you_know', NULL, 'EXO', 'exo', 'Each EXO member has their own dedicated sub-fandom', 'Baekhyun''s BBs, Kai''s Kaisers - all within the EXO-L universe', false, 'draft', ARRAY['#kpop', '#EXO', '#EXOL', '#kpoptrivia', '#kpopfandoms'], 'did_you_know', 146),
('Did You Know? Red Velvet Red vs Velvet', 'Did you know Red Velvet''s concept is split into two personalities? "Red" is upbeat and fun (like "Red Flavor"), while "Velvet" is dark and sophisticated (like "Peek-A-Boo"). Fans debate which concept is better. #RV', 'K-pop Fun Facts', 'did_you_know', NULL, 'Red Velvet', 'red-velvet', 'Fans still debate: Red concept vs. Velvet concept?', '"Red Flavor" brightness vs "Peek-A-Boo" darkness - which wins?', false, 'draft', ARRAY['#kpop', '#RedVelvet', '#ReVeluv', '#kpoptrivia', '#kpopfact'], 'did_you_know', 147),
('Did You Know? ASTRO Moonbin Passing', 'Did you know ASTRO lost beloved member Moonbin in April 2023? He passed away at 25 years old, leaving a profound impact on the K-pop community and his group. His memory lives on with AROHA. #ASTRO', 'K-pop Fun Facts', 'did_you_know', NULL, 'ASTRO', 'astro', 'ASTRO lost beloved member Moonbin in April 2023', 'His memory lives on through his music and AROHA''s love', false, 'draft', ARRAY['#kpop', '#ASTRO', '#Moonbin', '#AROHA', '#kpoptrivia'], 'did_you_know', 148),
('Did You Know? SEVENTEEN Made Fan Uniforms', 'Did you know SEVENTEEN made the concept of "fan-made light sticks" popular? Their "Carat Bong" was designed with help from fan input, creating one of the most interactive fandoms in K-pop. #SVT', 'K-pop Fun Facts', 'did_you_know', NULL, 'SEVENTEEN', 'seventeen', 'SEVENTEEN designed their light stick with fan input', 'The "Carat Bong" is one of K-pop''s most beloved fan lightsticks', false, 'draft', ARRAY['#kpop', '#SEVENTEEN', '#CARAT', '#kpoptrivia', '#kpopfandom'], 'did_you_know', 149),
('Did You Know? Kep1er Has a Fixed Contract', 'Did you know Kep1er was formed with a fixed 2.5-year group contract from the start? Formed through "Girls Planet 999" in 2021, the members knew from day one that the group had a set end date. #Kep1er', 'K-pop Fun Facts', 'did_you_know', NULL, 'Kep1er', 'kep1er', 'Kep1er was formed with a fixed 2.5-year contract', 'Members knew from day one this was a time-limited project', false, 'draft', ARRAY['#kpop', '#Kep1er', '#Kep1ian', '#kpoptrivia', '#kpopfact'], 'did_you_know', 150),
('Did You Know? NCT 127 Number Meaning', 'Did you know "NCT 127" - the Seoul-based NCT unit - gets its number from the longitude coordinate of Seoul, South Korea? 127 degrees East is exactly Seoul''s geographic position. #NCT #kpoptrivia', 'K-pop Fun Facts', 'did_you_know', NULL, 'NCT', 'nct', 'NCT 127''s number comes from Seoul''s longitude coordinate', '127 degrees East is exactly where Seoul is on the map', false, 'draft', ARRAY['#kpop', '#NCT', '#NCT127', '#NCTzen', '#kpoptrivia'], 'did_you_know', 151),
('Did You Know? NewJeans 5 MVs at Once', 'Did you know NewJeans released their debut music video "Hype Boy" in 4 separate versions - one for each member - at the exact same time? This unconventional strategy became a huge viral moment. #NewJeans', 'K-pop Fun Facts', 'did_you_know', NULL, 'NewJeans', 'newjeans', '"Hype Boy" launched as 4 separate music videos at once', 'Each version centered on one member - all released simultaneously', false, 'draft', ARRAY['#kpop', '#NewJeans', '#HypeBoy', '#Bunnies', '#kpoptrivia'], 'did_you_know', 152),
('Did You Know? MAMAMOO Won Without Company Push', 'Did you know MAMAMOO built most of their popularity without the backing of a major entertainment company? RBW Entertainment was small when they debuted, making their success largely fan-driven. #MAMAMOO', 'K-pop Fun Facts', 'did_you_know', NULL, 'MAMAMOO', 'mamamoo', 'MAMAMOO built their success without a big company behind them', 'RBW was a small label - their rise was largely fan-driven', false, 'draft', ARRAY['#kpop', '#MAMAMOO', '#Moomoo', '#kpoptrivia', '#kpopfact'], 'did_you_know', 153),
('Did You Know? GOT7 Made Their Own Label', 'Did you know after leaving JYP in 2021, GOT7 members collectively helped establish or join new labels? Jay B formed his own imprint and the group released music together independently in 2022. #GOT7', 'K-pop Fun Facts', 'did_you_know', NULL, 'GOT7', 'got7', 'After leaving JYP, GOT7 still released music together', 'They proved a group can thrive independently', false, 'draft', ARRAY['#kpop', '#GOT7', '#IGOT7', '#kpoptrivia', '#kpophistory'], 'did_you_know', 154),
('Did You Know? STAYC High Up Entertainment Fact', 'Did you know STAYC''s label High Up Entertainment was co-founded by Steven Lee and Black Eyed Pilseung - the producer duo behind hits for TWICE, including "Cheer Up" and "TT". #STAYC #kpoptrivia', 'K-pop Fun Facts', 'did_you_know', NULL, 'STAYC', 'stayc', 'STAYC''s producers made TWICE''s "Cheer Up" and "TT"', 'Black Eyed Pilseung co-founded High Up Entertainment', false, 'draft', ARRAY['#kpop', '#STAYC', '#SWITH', '#kpoptrivia', '#kpopproducer'], 'did_you_know', 155),
('Did You Know? BTS Boy In Luv Almost Scrapped', 'Did you know BTS almost didn''t release "Boy In Luv" in 2014? According to RM, the song nearly got scrapped during production. It went on to be one of their breakthrough hits. #BTS #kpoptrivia', 'K-pop Fun Facts', 'did_you_know', NULL, 'BTS', 'bts', 'BTS almost didn''t release "Boy In Luv" in 2014', 'It nearly got scrapped - and became a breakthrough hit', false, 'draft', ARRAY['#kpop', '#BTS', '#ARMY', '#kpoptrivia', '#kpophistory'], 'did_you_know', 156),
('Did You Know? TREASURE Has the Most YG Trainees', 'Did you know TREASURE was selected from over 100 YG trainees who competed on the "YG Treasure Box" survival show? The show ran for weeks before the final 12-member lineup was revealed. #TREASURE', 'K-pop Fun Facts', 'did_you_know', NULL, 'TREASURE', 'treasure', '100+ YG trainees competed to become TREASURE', 'The survival show ran weeks before the final 12 were chosen', false, 'draft', ARRAY['#kpop', '#TREASURE', '#Teume', '#kpoptrivia', '#YGEntertainment'], 'did_you_know', 157),
('Did You Know? ENHYPEN Concept Is Vampires', 'Did you know ENHYPEN''s concept centers around vampires and the theme of "crossing the threshold"? Their debut album "Border: Day One" introduced a lore about humans becoming vampires. #ENHYPEN', 'K-pop Fun Facts', 'did_you_know', NULL, 'ENHYPEN', 'enhypen', 'ENHYPEN''s concept is about crossing the threshold - like vampires', 'Their debut lore explored humans becoming something immortal', false, 'draft', ARRAY['#kpop', '#ENHYPEN', '#ENGENE', '#kpoptrivia', '#kpoplore'], 'did_you_know', 158),
('Did You Know? ATEEZ Performed in US Pre-Deal', 'Did you know ATEEZ performed multiple sold-out US tours before they had a major US label distribution deal? They built their American fanbase almost entirely through grassroots touring. #ATEEZ #kpoptrivia', 'K-pop Fun Facts', 'did_you_know', NULL, 'ATEEZ', 'ateez', 'ATEEZ sold out US tours before signing a US label deal', 'They built their American fanbase entirely through touring', false, 'draft', ARRAY['#kpop', '#ATEEZ', '#ATINY', '#kpoptrivia', '#kpophistory'], 'did_you_know', 159),
('Did You Know? K-pop Idol Training Can Take Years', 'Did you know K-pop idols often train for 3-7 years before debuting? BTS''s Jin trained for less than a year, while Bang Chan of Stray Kids trained at JYP for 7 years before debuting. #kpop #kpoptrivia', 'K-pop Fun Facts', 'did_you_know', NULL, NULL, NULL, 'Some K-pop idols train for 7+ years before debuting', 'BTS''s Jin trained less than a year; Bang Chan trained 7 years', false, 'draft', ARRAY['#kpop', '#kpoptrivia', '#kpoptraining', '#kpopfact', '#kpopindustry'], 'did_you_know', 160);
